--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -555,6 +555,80 @@
 function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
   const ft: Record<CharacterType, string> = {
     king: 'carpet', nobility: 'wood', knight: 'wood', squire: 'wood',
     healer: 'dark_stone', sentinel: 'stone', scribe: 'wood', judge: 'wood', blacksmith: 'stone',
   };
   const tile = 16;
   const kind = ft[type];
+}
+
+// ─── Room transition animations ─────────────────────────────────────────────
+
+export function drawDoorway(ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number) {
+  // Draw a dark archway doorway with a subtle gradient
+  const archHeight = height * 0.6;
+  const archWidth = width;
+  const archX = x;
+  const archY = y + height - archHeight;
+
+  // Doorway base rectangle
+  ctx.fillStyle = '#0a0a0a';
+  ctx.fillRect(archX, archY, archWidth, archHeight);
+
+  // Arch curve
+  ctx.beginPath();
+  ctx.moveTo(archX, archY + archHeight);
+  ctx.lineTo(archX, archY + archHeight * 0.5);
+  ctx.quadraticCurveTo(archX + archWidth / 2, archY, archX + archWidth, archY + archHeight * 0.5);
+  ctx.lineTo(archX + archWidth, archY + archHeight);
+  ctx.closePath();
+
+  const grad = ctx.createLinearGradient(archX, archY, archX, archY + archHeight);
+  grad.addColorStop(0, '#111111');
+  grad.addColorStop(1, '#000000');
+  ctx.fillStyle = grad;
+  ctx.fill();
+
+  // Inner shadow to give depth
+  ctx.strokeStyle = 'rgba(0,0,0,0.8)';
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(archX, archY + archHeight);
+  ctx.lineTo(archX, archY + archHeight * 0.5);
+  ctx.quadraticCurveTo(archX + archWidth / 2, archY + archHeight * 0.15, archX + archWidth, archY + archHeight * 0.5);
+  ctx.lineTo(archX + archWidth, archY + archHeight);
+  ctx.stroke();
+}
+
+interface Room {
+  x: number;
+  y: number;
+  w: number;
+  h: number;
+}
+
+export function drawCorridor(ctx: CanvasRenderingContext2D, fromRoom: Room, toRoom: Room) {
+  // Draw a corridor connecting adjacent rooms
+  ctx.fillStyle = '#222222';
+  ctx.strokeStyle = '#111111';
+  ctx.lineWidth = 2;
+
+  // Determine corridor orientation and position
+  const fromRight = fromRoom.x + fromRoom.w;
+  const fromBottom = fromRoom.y + fromRoom.h;
+  const toRight = toRoom.x + toRoom.w;
+  const toBottom = toRoom.y + toRoom.h;
+
+  // Horizontal corridor
+  if (fromRoom.y === toRoom.y && (fromRight === toRoom.x || toRight === fromRoom.x)) {
+    // Adjacent horizontally
+    const corridorY = fromRoom.y + fromRoom.h * 0.5 - 8;
+    const corridorX = Math.min(fromRight, toRight);
+    const corridorW = Math.abs(toRoom.x - fromRoom.x);
+    const corridorH = 16;
+    ctx.fillRect(corridorX, corridorY, corridorW, corridorH);
+    ctx.strokeRect(corridorX, corridorY, corridorW, corridorH);
+    // Draw doorways at edges
+    drawDoorway(ctx, corridorX - 8, corridorY, 16, corridorH);
+    drawDoorway(ctx, corridorX + corridorW - 8, corridorY, 16, corridorH);
+  }
+  // Vertical corridor
+  else if (fromRoom.x === toRoom.x && (fromBottom === toRoom.y || toBottom === fromRoom.y)) {
+    // Adjacent vertically
+    const corridorX = fromRoom.x + fromRoom.w * 0.5 - 8;
+    const corridorY = Math.min(fromBottom, toBottom);
+    const corridorW = 16;
+    const corridorH = Math.abs(toRoom.y - fromRoom.y);
+    ctx.fillRect(corridorX, corridorY, corridorW, corridorH);
+    ctx.strokeRect(corridorX, corridorY, corridorW, corridorH);
+    // Draw doorways at edges
+    drawDoorway(ctx, corridorX, corridorY - 8, corridorW, 16);
+    drawDoorway(ctx, corridorX, corridorY + corridorH - 8, corridorW, 16);
+  }
+}
+
+// Fade-in effect for room redraw
+export function drawRoomWithFadeIn(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  x: number,
+  y: number,
+  w: number,
+  h: number,
+  frame: number,
+  totalFrames = 5,
+) {
+  const opacity = Math.min(1, (frame + 1) / totalFrames);
+  ctx.save();
+  ctx.globalAlpha = opacity;
+  drawRoom(ctx, type, x, y, w, h, frame);
+  ctx.restore();
+}
